import React, { createContext, useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { onSnapshot, doc } from 'firebase/firestore';
import { getDb } from '../firebase';
import { api } from '../services/api';
import { WORKFLOW_STAGES, STAGE_CONFIG } from '../workflow/stages';

// --- Canonical Models ---

/**
 * @typedef {object} Session The central document tracking the user's journey.
 * @property {string} id
 * @property {string} currentStage The current stage of the workflow (e.g., 'formulate_problem').
 * @property {string} goal The user's initial high-level goal.
 * @property {object} [summary] A computed summary of the session's state.
 * @property {string | null} [formulationId]
 * @property {string | null} [recommendationId]
 * @property {string | null} [solverInputId]
 * @property {string | null} [executionId]
 * @property {string | null} [resultId]
 * @property {firebase.firestore.Timestamp} createdAt
 */

/**
 * @typedef {object} Artifacts Holds the fully-loaded data for all artifacts linked in the session.
 * @property {any} formulation
 * @property {any} recommendation
 * @property {any} solverInput
 * @property {any} execution
 * @property {any} result
 */

/**
 * @typedef {object} SessionContextValue
 * @property {Session | null} session
 * @property {Artifacts} artifacts
 * @property {object | null} currentStageConfig
 * @property {boolean} loading
 * @property {Error | null} error
 * @property {(goal: string) => Promise<void>} startNewSession
 * @property {(sessionId: string, stage: string, data?: object) => Promise<void>} updateSession
 */

// --- React Context ---

export const SessionContext = createContext(/** @type {SessionContextValue} */ ({
    session: null,
    artifacts: { formulation: null, recommendation: null, solverInput: null, execution: null, result: null },
    currentStageConfig: null,
    loading: true,
    error: null,
    startNewSession: async () => {},
    updateSession: async () => {},
}));

export const SessionProvider = ({ children }) => {
    const [session, setSession] = useState(null);
    const [artifacts, setArtifacts] = useState({ formulation: null, recommendation: null, solverInput: null, execution: null, result: null });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [currentStageConfig, setCurrentStageConfig] = useState(null);
    const navigate = useNavigate();
    const location = useLocation();

    const resetState = useCallback(() => {
        setSession(null);
        setArtifacts({ formulation: null, recommendation: null, solverInput: null, execution: null, result: null });
        setCurrentStageConfig(null);
        setLoading(false);
        setError(null);
    }, []);

    const loadAllArtifacts = useCallback(async (sessionData) => {
        if (!sessionData) return;
        setLoading(true);
        try {
            const artifactPromises = {
                formulation: sessionData.formulationId ? api.getFormulation(sessionData.formulationId) : Promise.resolve(null),
                recommendation: sessionData.recommendationId ? api.getRecommendation(sessionData.recommendationId) : Promise.resolve(null),
                solverInput: sessionData.solverInputId ? api.getSolverInput(sessionData.solverInputId) : Promise.resolve(null),
                execution: sessionData.executionId ? api.getExecution(sessionData.executionId) : Promise.resolve(null),
                result: sessionData.resultId ? api.getResult(sessionData.resultId) : Promise.resolve(null),
            };

            const loadedArtifacts = {
                formulation: await artifactPromises.formulation,
                recommendation: await artifactPromises.recommendation,
                solverInput: await artifactPromises.solverInput,
                execution: await artifactPromises.execution,
                result: await artifactPromises.result,
            };

            setArtifacts(loadedArtifacts);
        } catch (err) {
            console.error("Error loading one or more artifacts:", err);
            setError(err);
        } finally {
            setLoading(false);
        }
    }, []);

    // Main effect to listen for session changes from URL
    useEffect(() => {
        const params = new URLSearchParams(location.search);
        const sessionId = params.get('session');
        const db = getDb();

        if (!sessionId) {
            resetState();
            return;
        }

        if (session?.id === sessionId) {
            return; // Already listening to this session
        }

        setLoading(true);
        const sessionRef = doc(db, 'sessions', sessionId);

        const unsubscribe = onSnapshot(sessionRef, async (docSnap) => {
            if (docSnap.exists()) {
                const sessionData = { id: docSnap.id, ...docSnap.data() };
                setSession(sessionData);
                await loadAllArtifacts(sessionData);

                const stageConfig = STAGE_CONFIG[sessionData.currentStage] || null;
                setCurrentStageConfig(stageConfig);

                // Navigate to the correct page for the session's stage to ensure coherence
                const expectedPath = stageConfig?.path;
                if (expectedPath && location.pathname !== expectedPath) {
                   // Only navigate if we are not already on a page for this session
                   if (!location.pathname.includes(expectedPath.substring(1))) {
                        navigate(`${expectedPath}?session=${sessionId}`);
                   }
                }

            } else {
                console.error("Session not found:", sessionId);
                setError(new Error("Session not found"));
                resetState();
                navigate('/');
            }
            setLoading(false);
        }, (err) => {
            console.error("Error listening to session:", err);
            setError(err);
            resetState();
            navigate('/');
        });

        return () => unsubscribe();
    }, [location.search, navigate, session?.id]);


    const startNewSession = useCallback(async (goal) => {
        if (!goal) return;
        setLoading(true);
        try {
            const { sessionId } = await api.createSession({ 
                goal,
                currentStage: WORKFLOW_STAGES.DEFINE_GOAL 
            });
            const stageConfig = STAGE_CONFIG[WORKFLOW_STAGES.DEFINE_GOAL];
            navigate(`${stageConfig.path}?session=${sessionId}`);
        } catch (error) {
            console.error("Error starting new session:", error);
            setError(error);
        } finally {
            setLoading(false);
        }
    }, [navigate]);

    const updateSession = useCallback(async (sessionId, stage, data = {}) => {
        setLoading(true);
        try {
            await api.updateSession(sessionId, { currentStage: stage, ...data });
            // The onSnapshot listener will handle the state update and navigation
        } catch(err) {
            console.error(`Error updating session to stage ${stage}:`, err);
            setError(err);
        } finally {
            setLoading(false);
        }
    }, []);

    const value = {
        session,
        artifacts,
        loading,
        error,
        currentStageConfig,
        startNewSession,
        updateSession,
    };

    return (
        <SessionContext.Provider value={value}>
            {children}
        </SessionContext.Provider>
    );
};
